mapper.select:
SELECT FROM cart c JOIN sku s ON c.sku_id = s.id JOIN product p ON s.product_id = p.id LEFT JOIN merchant m ON p.merchant_id = m.id WHERE c.user_id = #{userId} AND c.id IN
#{cartItemId}
ORDER BY c.id DESC

mapper.update:
UPDATE cart
SET quantity = #{quantity}
WHERE id = #{id} AND user_id = #{userId}

mapper.delete:
